import{c as h,S as i,j as a,m as t}from"./chunks/framework.8aa1YH_s.js";const k=JSON.parse('{"title":"Quản lý khóa học (Giáo viên)","description":"","frontmatter":{},"headers":[],"relativePath":"giao-vien/quan-ly-khoa-hoc.md","filePath":"giao-vien/quan-ly-khoa-hoc.md","lastUpdated":0}'),o={name:"giao-vien/quan-ly-khoa-hoc.md"};function c(l,n,r,g,e,s){return i(),a("div",null,[...n[0]||(n[0]=[t('<h1 id="quan-ly-khoa-hoc-giao-vien" tabindex="-1">Quản lý khóa học (Giáo viên) <a class="header-anchor" href="#quan-ly-khoa-hoc-giao-vien" aria-label="Permalink to “Quản lý khóa học (Giáo viên)”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/teacher/course-management</code></p><p>Đây là <strong>trang chính</strong> của giáo viên. Mọi thao tác tạo khóa, soạn nội dung, gắn đề thi, công khai khóa đều bắt đầu từ đây.</p><h2 id="danh-sach-khoa-cua-ban" tabindex="-1">Danh sách khóa của bạn <a class="header-anchor" href="#danh-sach-khoa-cua-ban" aria-label="Permalink to “Danh sách khóa của bạn”">​</a></h2><p>Bạn chỉ thấy các khóa do <strong>mình phụ trách</strong> (Admin gán). Cột chính:</p><ul><li>Tên khóa</li><li>Khung chương trình</li><li>Loại khóa (Nền tảng / Chuyên đề / Thực chiến)</li><li>Số chương / chuyên đề / bài giảng</li><li>Số học viên đang học</li><li>Giá</li><li>Trạng thái (Nháp / Công khai / Ẩn)</li><li>Thao tác (Sửa / Xem chi tiết / Sao chép / Ẩn)</li></ul><h2 id="tao-khoa-hoc-moi" tabindex="-1">Tạo khóa học mới <a class="header-anchor" href="#tao-khoa-hoc-moi" aria-label="Permalink to “Tạo khóa học mới”">​</a></h2><blockquote><p>⚠️ Tùy hệ thống, có nơi chỉ Admin được tạo khóa rồi giao cho giáo viên. Nếu bạn có nút <strong>Thêm khóa</strong>, hãy theo các bước sau.</p></blockquote><ol><li>Bấm <strong>Thêm khóa</strong>.</li><li>Trang <code>https://lamsonedutech.vn/teacher/form-course/:idCourse</code> mở ra với form khai báo: <ul><li><strong>Tên khóa</strong></li><li><strong>Khung chương trình</strong> (chọn từ dropdown)</li><li><strong>Loại khóa</strong>: Ôn luyện nền tảng / Ôn luyện chuyên đề / Luyện đề thi thực chiến</li><li><strong>Ảnh bìa</strong>, <strong>Mô tả ngắn</strong></li><li><strong>Mô tả chi tiết</strong> (rich text)</li><li><strong>Giá gốc</strong>, <strong>Giá khuyến mãi</strong></li><li><strong>Thời gian sử dụng</strong> (số ngày)</li><li><strong>Cho phép học thử bao nhiêu phút?</strong></li></ul></li><li><strong>Lưu</strong> dưới dạng nháp.</li></ol><h2 id="chi-tiet-khoa-hoc" tabindex="-1">Chi tiết khóa học <a class="header-anchor" href="#chi-tiet-khoa-hoc" aria-label="Permalink to “Chi tiết khóa học”">​</a></h2><p><code>https://lamsonedutech.vn/teacher/detail-course/:idCourse</code></p><p>Trong trang chi tiết, bạn có các tab:</p><h3 id="_1-thong-tin-chung" tabindex="-1">1. Thông tin chung <a class="header-anchor" href="#_1-thong-tin-chung" aria-label="Permalink to “1. Thông tin chung”">​</a></h3><ul><li>Toàn bộ thông tin đã khai báo khi tạo.</li><li>Có thể chỉnh sửa bất cứ lúc nào.</li></ul><h3 id="_2-cau-truc-noi-dung" tabindex="-1">2. Cấu trúc nội dung <a class="header-anchor" href="#_2-cau-truc-noi-dung" aria-label="Permalink to “2. Cấu trúc nội dung”">​</a></h3><ul><li>Cây <strong>Chương → Chuyên đề → Bài giảng</strong>.</li><li>Bấm <strong>Thêm chương</strong> → đặt tên chương + thứ tự.</li><li>Trong chương, bấm <strong>Thêm chuyên đề</strong>.</li><li>Trong chuyên đề, có thể thêm <strong>Bài giảng</strong> và <strong>Đề kiểm tra cuối chuyên đề</strong>.</li><li>Kéo-thả để đổi thứ tự.</li></ul><p>→ Xem chi tiết: <a href="./soan-bai-giang">Soạn chương / chuyên đề / bài giảng</a>.</p><h3 id="_3-đe-thi" tabindex="-1">3. Đề thi <a class="header-anchor" href="#_3-đe-thi" aria-label="Permalink to “3. Đề thi”">​</a></h3><ul><li>Tổng hợp các đề thi đã gắn vào khóa: đề ôn khóa học, đề kiểm tra chuyên đề, đề mẫu luyện thi.</li><li>Có thể tạo đề mới hoặc liên kết đề đã có.</li></ul><h3 id="_4-lop-hoc" tabindex="-1">4. Lớp học <a class="header-anchor" href="#_4-lop-hoc" aria-label="Permalink to “4. Lớp học”">​</a></h3><ul><li>Danh sách các lớp đang dùng khóa này.</li><li>Mở từng lớp để vào <a href="./quan-ly-lop-hoc">Quản lý lớp học</a>.</li></ul><h3 id="_5-hoc-vien" tabindex="-1">5. Học viên <a class="header-anchor" href="#_5-hoc-vien" aria-label="Permalink to “5. Học viên”">​</a></h3><ul><li>Toàn bộ học viên đã mua / được gán khóa này (không phân theo lớp).</li><li>Cột: tên, SĐT, ngày bắt đầu, tiến độ học (%), điểm trung bình.</li><li>Bấm vào học viên để xem <strong>chi tiết tiến độ và điểm thi</strong> của họ.</li></ul><h3 id="_6-thao-luan-hoi-đap-khoa" tabindex="-1">6. Thảo luận / Hỏi đáp khóa <a class="header-anchor" href="#_6-thao-luan-hoi-đap-khoa" aria-label="Permalink to “6. Thảo luận / Hỏi đáp khóa”">​</a></h3><ul><li>Câu hỏi học viên đặt riêng cho khóa này (link sang <a href="./hoi-dap">Hỏi đáp</a>).</li></ul><h3 id="_7-bao-cao-thong-ke" tabindex="-1">7. Báo cáo / Thống kê <a class="header-anchor" href="#_7-bao-cao-thong-ke" aria-label="Permalink to “7. Báo cáo / Thống kê”">​</a></h3><ul><li>Số học viên hoàn thành.</li><li>Điểm trung bình theo chuyên đề.</li><li>Tỷ lệ học viên hoạt động tuần này.</li></ul><h2 id="sao-chep-khoa" tabindex="-1">Sao chép khóa <a class="header-anchor" href="#sao-chep-khoa" aria-label="Permalink to “Sao chép khóa”">​</a></h2><p>Khi cần tạo khóa tương tự (ví dụ năm sau):</p><ol><li>Trên dòng khóa, bấm <strong>... → Sao chép</strong>.</li><li>Đặt tên mới và chọn khung chương trình.</li><li>Hệ thống copy cấu trúc + bài giảng + đề (giữ link video).</li><li>Mở khóa mới → chỉnh nội dung cho phù hợp năm mới.</li></ol><h2 id="cong-khai-khoa" tabindex="-1">Công khai khóa <a class="header-anchor" href="#cong-khai-khoa" aria-label="Permalink to “Công khai khóa”">​</a></h2><p>Sau khi nội dung và đề thi hoàn thiện:</p><ol><li>Vào tab <strong>Thông tin chung</strong>.</li><li>Chọn trạng thái <strong>Công khai</strong>.</li><li>Lưu.</li><li>Khóa hiển thị trên trang chủ học viên (nếu khung chương trình cũng đang công khai).</li></ol><blockquote><p>💡 Trước khi công khai, hãy <strong>đăng nhập bằng tài khoản học viên test</strong> để xem giao diện thực tế. Tránh sai sót đáng tiếc.</p></blockquote><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Tôi không thấy nút &quot;Thêm khóa&quot;.</strong> → Hệ thống có thể chỉ cho Admin tạo khóa. Liên hệ Admin để được giao quyền.</p><p><strong>Khóa nháp đã có học viên test, nay muốn xóa khóa.</strong> → Đề nghị Admin can thiệp - xóa khóa kèm dữ liệu test.</p><p><strong>Tôi muốn cộng tác với giáo viên khác trong cùng 1 khóa.</strong> → Hệ thống hiện gán 1 giáo viên chính. Bạn có thể chia sẻ tài khoản hoặc nhờ Admin thiết lập tính năng đồng giảng (nếu phiên bản hỗ trợ).</p>',38)])])}const d=h(o,[["render",c]]);export{k as __pageData,d as default};
